/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements template rendering per notification type, recipient validation,
 * and configurable sender/reply-to. Stores sent emails in memory for
 * inspection (swap with a real SMTP/API transport for production).
 *
 * Implements the NotificationAdapter interface as required by the
 * notification system architecture.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult, NotificationChannel, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  from: string;
  replyTo?: string;
}

const defaultEmailConfig: EmailConfig = {
  from: 'noreply@taskflowpro.com',
};

/**
 * A rendered email ready for delivery.
 */
export interface RenderedEmail {
  from: string;
  replyTo?: string;
  to: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Template definitions keyed by notification type.
 * Each template receives the payload and returns { subject, html, text }.
 */
type TemplateRenderer = (payload: NotificationPayload) => { subject: string; html: string; text: string };

const templates: Record<NotificationType, TemplateRenderer> = {
  order_confirmation(payload) {
    const html = [
      `<h1>Order Confirmation</h1>`,
      `<p>Hello,</p>`,
      `<p>${payload.body}</p>`,
      `<p>If you have any questions, reply to this email.</p>`,
      `<p>— The TaskFlow Pro Team</p>`,
    ].join('\n');

    const text = [
      'Order Confirmation',
      '',
      payload.body,
      '',
      'If you have any questions, reply to this email.',
      '— The TaskFlow Pro Team',
    ].join('\n');

    return { subject: payload.subject, html, text };
  },

  order_status_update(payload) {
    const html = [
      `<h1>Order Status Update</h1>`,
      `<p>Hello,</p>`,
      `<p>${payload.body}</p>`,
      `<p>You can track your order in your account dashboard.</p>`,
      `<p>— The TaskFlow Pro Team</p>`,
    ].join('\n');

    const text = [
      'Order Status Update',
      '',
      payload.body,
      '',
      'You can track your order in your account dashboard.',
      '— The TaskFlow Pro Team',
    ].join('\n');

    return { subject: payload.subject, html, text };
  },

  user_welcome(payload) {
    const html = [
      `<h1>Welcome to TaskFlow Pro!</h1>`,
      `<p>Hello,</p>`,
      `<p>${payload.body}</p>`,
      `<p>Get started by visiting your dashboard.</p>`,
      `<p>— The TaskFlow Pro Team</p>`,
    ].join('\n');

    const text = [
      'Welcome to TaskFlow Pro!',
      '',
      payload.body,
      '',
      'Get started by visiting your dashboard.',
      '— The TaskFlow Pro Team',
    ].join('\n');

    return { subject: payload.subject, html, text };
  },

  user_updated(payload) {
    const html = [
      `<h1>Account Updated</h1>`,
      `<p>Hello,</p>`,
      `<p>${payload.body}</p>`,
      `<p>If you did not make this change, contact support immediately.</p>`,
      `<p>— The TaskFlow Pro Team</p>`,
    ].join('\n');

    const text = [
      'Account Updated',
      '',
      payload.body,
      '',
      'If you did not make this change, contact support immediately.',
      '— The TaskFlow Pro Team',
    ].join('\n');

    return { subject: payload.subject, html, text };
  },
};

// Simple email regex: local@domain with at least one dot in domain
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: RenderedEmail[] = [];
  private config: EmailConfig;

  constructor(config: EmailConfig = defaultEmailConfig) {
    this.config = config;
  }

  /**
   * Validate that a recipient string is a well-formed email address.
   */
  validateRecipient(recipient: string): string | null {
    if (!recipient || !EMAIL_REGEX.test(recipient)) {
      return `Invalid email address: ${recipient}`;
    }
    return null;
  }

  /**
   * Render the notification payload into a full email using the
   * template for the notification type.
   */
  renderEmail(payload: NotificationPayload): RenderedEmail {
    const renderer = templates[payload.type];
    const rendered = renderer(payload);

    return {
      from: this.config.from,
      replyTo: this.config.replyTo,
      to: payload.recipient,
      subject: rendered.subject,
      html: rendered.html,
      text: rendered.text,
    };
  }

  /**
   * Send a notification through the email channel.
   * Validates the recipient, renders the template, and delivers.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Preparing email to ${payload.recipient}: ${payload.subject}`);

    // Validate recipient
    const validationError = this.validateRecipient(payload.recipient);
    if (validationError) {
      this.logger.warn(`Validation failed for ${payload.id}: ${validationError}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: validationError,
      };
    }

    // Render template
    const email = this.renderEmail(payload);

    // Deliver (in-memory store; replace with SMTP/API call in production)
    this.sentEmails.push(email);

    this.logger.info(
      `Email delivered: ${payload.id} from ${email.from} to ${email.to}`,
    );

    return {
      success: true,
      notificationId: payload.id,
      channel: this.channel,
    };
  }

  /**
   * Get all emails sent through this adapter (for testing).
   */
  getSentEmails(): RenderedEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history (for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    createdAt: new Date(),
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter();
  });

  describe('channel', () => {
    it('should identify as email channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('validateRecipient', () => {
    it('should accept valid email addresses', () => {
      expect(adapter.validateRecipient('alice@example.com')).toBeNull();
      expect(adapter.validateRecipient('bob+tag@sub.domain.org')).toBeNull();
    });

    it('should reject empty string', () => {
      expect(adapter.validateRecipient('')).toContain('Invalid email');
    });

    it('should reject address without @', () => {
      expect(adapter.validateRecipient('alice-at-example.com')).toContain('Invalid email');
    });

    it('should reject address without domain dot', () => {
      expect(adapter.validateRecipient('alice@example')).toContain('Invalid email');
    });

    it('should reject address with spaces', () => {
      expect(adapter.validateRecipient('alice @example.com')).toContain('Invalid email');
    });
  });

  describe('renderEmail', () => {
    it('should render order_confirmation template', () => {
      const payload = makePayload({ type: 'order_confirmation' });
      const email = adapter.renderEmail(payload);

      expect(email.from).toBe('noreply@taskflowpro.com');
      expect(email.to).toBe('alice@example.com');
      expect(email.subject).toBe(payload.subject);
      expect(email.html).toContain('<h1>Order Confirmation</h1>');
      expect(email.html).toContain(payload.body);
      expect(email.text).toContain('Order Confirmation');
      expect(email.text).toContain(payload.body);
    });

    it('should render order_status_update template', () => {
      const payload = makePayload({
        type: 'order_status_update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
      });
      const email = adapter.renderEmail(payload);

      expect(email.html).toContain('<h1>Order Status Update</h1>');
      expect(email.html).toContain('pending to confirmed');
      expect(email.text).toContain('track your order');
    });

    it('should render user_welcome template', () => {
      const payload = makePayload({
        type: 'user_welcome',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro, Alice!',
      });
      const email = adapter.renderEmail(payload);

      expect(email.html).toContain('<h1>Welcome to TaskFlow Pro!</h1>');
      expect(email.text).toContain('Get started');
    });

    it('should render user_updated template', () => {
      const payload = makePayload({
        type: 'user_updated',
        subject: 'Account Updated',
        body: 'Your email address has been changed.',
      });
      const email = adapter.renderEmail(payload);

      expect(email.html).toContain('<h1>Account Updated</h1>');
      expect(email.text).toContain('contact support');
    });

    it('should use custom config for from/replyTo', () => {
      const custom = new EmailAdapter({ from: 'team@acme.co', replyTo: 'support@acme.co' });
      const email = custom.renderEmail(makePayload());

      expect(email.from).toBe('team@acme.co');
      expect(email.replyTo).toBe('support@acme.co');
    });

    it('should omit replyTo when not configured', () => {
      const email = adapter.renderEmail(makePayload());
      expect(email.replyTo).toBeUndefined();
    });
  });

  describe('send', () => {
    it('should send successfully for valid recipient', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('email');
      expect(result.error).toBeUndefined();
    });

    it('should store rendered email on success', async () => {
      await adapter.send(makePayload());

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.from).toBe('noreply@taskflowpro.com');
      expect(sent[0]?.html).toContain('<h1>');
    });

    it('should fail for invalid email address', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email');
    });

    it('should not store email on validation failure', async () => {
      await adapter.send(makePayload({ recipient: 'bad' }));
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should handle multiple sends', async () => {
      await adapter.send(makePayload({ id: 'n-1', recipient: 'a@b.com' }));
      await adapter.send(makePayload({ id: 'n-2', recipient: 'c@d.com' }));

      expect(adapter.getSentEmails()).toHaveLength(2);
    });
  });

  describe('getSentEmails / clearSentEmails', () => {
    it('should return a copy of sent emails', async () => {
      await adapter.send(makePayload());
      const first = adapter.getSentEmails();
      const second = adapter.getSentEmails();
      expect(first).not.toBe(second);
      expect(first).toEqual(second);
    });

    it('should clear all sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });
});

